namespace Components;

public class ShippingInfo
{
    public string Name { get; set; } = "";
    public string Address { get; set; } = "";
    public string City { get; set; } = "";
    public string ZipCode { get; set; } = "";
}

public class PaymentInfo
{
    public string CardNumber { get; set; } = "";
    public string ExpiryDate { get; set; } = "";
}

public class Order
{
    public ShippingInfo Shipping { get; set; } = new();
    public PaymentInfo Payment { get; set; } = new();
}

@namespace Components

<div class="checkout-wizard">
    @if (_step == 1)
    {
        <ShippingStep Shipping="@_order.Shipping" OnNext="@HandleNext" />
    }
    else if (_step == 2)
    {
        <PaymentStep Payment="@_order.Payment" OnBack="@HandleBack" OnPlaceOrder="@HandlePlaceOrder" />
    }
</div>

@code {
    [Parameter]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private Order _order = new();
    private int _step = 1;

    private void HandleNext()
    {
        _step = 2;
    }

    private void HandleBack()
    {
        _step = 1;
    }

    private async Task HandlePlaceOrder()
    {
        await OnOrderPlaced.InvokeAsync(_order);
    }
}

@namespace Components

<h3>Shipping Information</h3>

<div class="form-group">
    <label for="name">Name</label>
    <input id="name" @bind="Shipping.Name" @bind:event="oninput" />
</div>

<div class="form-group">
    <label for="address">Address</label>
    <input id="address" @bind="Shipping.Address" @bind:event="oninput" />
</div>

<div class="form-group">
    <label for="city">City</label>
    <input id="city" @bind="Shipping.City" @bind:event="oninput" />
</div>

<div class="form-group">
    <label for="zipcode">Zip Code</label>
    <input id="zipcode" @bind="Shipping.ZipCode" @bind:event="oninput" />
</div>

@if (!string.IsNullOrWhiteSpace(_validationMessage))
{
    <p class="validation-error">@_validationMessage</p>
}

<button @onclick="HandleNext">Next</button>

@code {
    [Parameter]
    public ShippingInfo Shipping { get; set; } = new();

    [Parameter]
    public EventCallback OnNext { get; set; }

    private string _validationMessage = "";

    private async Task HandleNext()
    {
        if (string.IsNullOrWhiteSpace(Shipping.Name))
        {
            _validationMessage = "Name is required.";
            return;
        }

        if (string.IsNullOrWhiteSpace(Shipping.Address))
        {
            _validationMessage = "Address is required.";
            return;
        }

        _validationMessage = "";
        await OnNext.InvokeAsync();
    }
}

@namespace Components

<h3>Payment Information</h3>

<div class="form-group">
    <label for="cardnumber">Card Number</label>
    <input id="cardnumber" @bind="Payment.CardNumber" />
</div>

<div class="form-group">
    <label for="expiry">Expiry Date</label>
    <input id="expiry" @bind="Payment.ExpiryDate" />
</div>

<button @onclick="HandleBack">Back</button>
<button @onclick="HandlePlaceOrder">Place Order</button>

@code {
    [Parameter]
    public PaymentInfo Payment { get; set; } = new();

    [Parameter]
